export const html: string = "<section id=\"setup\">\n<div class=\"section-header\">\n<span class=\"section-num\">01</span>\n<h2>Project Setup</h2>\n</div>\n<h3>Installation &amp; Virtual Environment</h3>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">bash</span></div>\n<pre><span># Create and activate a virtual environment</span>\npython -m venv .venv\nsource .venv/bin/activate <span># Windows: .venv\\Scripts\\activate</span>\n\n<span># Install core packages</span>\npip install django <span># core</span>\npip install djangorestframework <span># REST API</span>\npip install django-environ <span># env vars</span>\npip install psycopg2-binary <span># PostgreSQL</span>\npip install pillow <span># image handling</span>\npip install celery redis <span># task queue</span>\npip install django-cors-headers <span># CORS</span>\n\npip freeze &gt; requirements.txt</pre>\n</div>\n<h3>Create Project &amp; App</h3>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">bash</span></div>\n<pre>django-admin startproject config . <span># '.' keeps flat layout</span>\npython manage.py startapp users\npython manage.py startapp products</pre>\n</div>\n</section>\n<section id=\"structure\">\n<div class=\"section-header\">\n<span class=\"section-num\">02</span>\n<h2>Project Structure</h2>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">recommended layout</span></div>\n<pre>myproject/\n\u251c\u2500\u2500 config/ <span># project package (replaces \"myproject\")</span>\n\u2502 \u251c\u2500\u2500 settings/\n\u2502 \u2502 \u251c\u2500\u2500 base.py\n\u2502 \u2502 \u251c\u2500\u2500 development.py\n\u2502 \u2502 \u2514\u2500\u2500 production.py\n\u2502 \u251c\u2500\u2500 urls.py\n\u2502 \u251c\u2500\u2500 wsgi.py\n\u2502 \u2514\u2500\u2500 asgi.py\n\u251c\u2500\u2500 apps/\n\u2502 \u251c\u2500\u2500 users/ <span># each app is self-contained</span>\n\u2502 \u2502 \u251c\u2500\u2500 models.py\n\u2502 \u2502 \u251c\u2500\u2500 views.py\n\u2502 \u2502 \u251c\u2500\u2500 serializers.py\n\u2502 \u2502 \u251c\u2500\u2500 urls.py\n\u2502 \u2502 \u251c\u2500\u2500 admin.py\n\u2502 \u2502 \u251c\u2500\u2500 signals.py\n\u2502 \u2502 \u251c\u2500\u2500 tasks.py\n\u2502 \u2502 \u2514\u2500\u2500 tests/\n\u2502 \u2514\u2500\u2500 products/\n\u251c\u2500\u2500 static/\n\u251c\u2500\u2500 media/\n\u251c\u2500\u2500 templates/\n\u251c\u2500\u2500 .env\n\u251c\u2500\u2500 manage.py\n\u2514\u2500\u2500 requirements.txt</pre>\n</div>\n</section>\n<section id=\"settings\">\n<div class=\"section-header\">\n<span class=\"section-num\">03</span>\n<h2>Settings</h2>\n</div>\n<h3>settings/base.py \u2014 Core Config</h3>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python \u00b7 config/settings/base.py</span></div>\n<pre><span>import</span> environ\n<span>from</span> pathlib <span>import</span> Path\n\nenv <span>=</span> environ.<span>Env</span>(DEBUG<span>=</span>(bool, <span>False</span>))\nBASE_DIR <span>=</span> Path(<span>__file__</span>).resolve().parent.parent.parent\n\n<span># Read .env</span>\nenviron.Env.<span>read_env</span>(BASE_DIR <span>/</span> <span>'.env'</span>)\n\nSECRET_KEY <span>=</span> env(<span>'SECRET_KEY'</span>)\nDEBUG <span>=</span> env(<span>'DEBUG'</span>)\nALLOWED_HOSTS <span>=</span> env.<span>list</span>(<span>'ALLOWED_HOSTS'</span>, default<span>=</span>[])\n\nINSTALLED_APPS <span>=</span> [\n <span># Django built-ins</span>\n <span>'django.contrib.admin'</span>,\n <span>'django.contrib.auth'</span>,\n <span>'django.contrib.contenttypes'</span>,\n <span>'django.contrib.sessions'</span>,\n <span>'django.contrib.messages'</span>,\n <span>'django.contrib.staticfiles'</span>,\n <span># Third-party</span>\n <span>'rest_framework'</span>,\n <span>'corsheaders'</span>,\n <span># Local apps</span>\n <span>'apps.users'</span>,\n <span>'apps.products'</span>,\n]\n\nDATABASES <span>=</span> {\n <span>'default'</span>: env.<span>db</span>(<span>'DATABASE_URL'</span>,\n default<span>=</span><span>'sqlite:///db.sqlite3'</span>)\n}\n\n<span># Static &amp; Media</span>\nSTATIC_URL <span>=</span> <span>'/static/'</span>\nSTATIC_ROOT <span>=</span> BASE_DIR <span>/</span> <span>'staticfiles'</span>\nMEDIA_URL <span>=</span> <span>'/media/'</span>\nMEDIA_ROOT <span>=</span> BASE_DIR <span>/</span> <span>'media'</span>\n\nDEFAULT_AUTO_FIELD <span>=</span> <span>'django.db.models.BigAutoField'</span>\n\n<span># Auth</span>\nAUTH_USER_MODEL <span>=</span> <span>'users.User'</span> <span># custom user</span></pre>\n</div>\n<div class=\"callout tone-tip\">\n<span class=\"callout-icon\"></span>\n<div class=\"callout-body\">\n<strong>Tip \u2014 Split settings</strong>\n Use <code>DJANGO_SETTINGS_MODULE=config.settings.production</code> in your environment to switch between dev/prod without touching code.\n </div>\n</div>\n</section>\n<section id=\"models\">\n<div class=\"section-header\">\n<span class=\"section-num\">04</span>\n<h2>Models</h2>\n</div>\n<h3>Custom User Model (always define early)</h3>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python \u00b7 users/models.py</span></div>\n<pre><span>from</span> django.contrib.auth.models <span>import</span> AbstractBaseUser, PermissionsMixin\n<span>from</span> django.db <span>import</span> models\n<span>from</span> django.utils <span>import</span> timezone\n<span>from</span> .managers <span>import</span> UserManager\n\n<span>class</span> <span>User</span>(AbstractBaseUser, PermissionsMixin):\n email <span>=</span> models.<span>EmailField</span>(unique<span>=</span><span>True</span>)\n first_name <span>=</span> models.<span>CharField</span>(max_length<span>=</span><span>150</span>, blank<span>=</span><span>True</span>)\n last_name <span>=</span> models.<span>CharField</span>(max_length<span>=</span><span>150</span>, blank<span>=</span><span>True</span>)\n is_active <span>=</span> models.<span>BooleanField</span>(default<span>=</span><span>True</span>)\n is_staff <span>=</span> models.<span>BooleanField</span>(default<span>=</span><span>False</span>)\n date_joined<span>=</span> models.<span>DateTimeField</span>(default<span>=</span>timezone.now)\n\n USERNAME_FIELD <span>=</span> <span>'email'</span>\n REQUIRED_FIELDS <span>=</span> []\n\n objects <span>=</span> <span>UserManager</span>()\n\n <span>class</span> <span>Meta</span>:\n verbose_name <span>=</span> <span>'user'</span>\n ordering <span>=</span> [<span>'-date_joined'</span>]\n\n <span>def</span> <span>get_full_name</span>(<span>self</span>):\n <span>return</span> <span>f'<span>{</span><span>self</span>.first_name<span>}</span> <span>{</span><span>self</span>.last_name<span>}</span>'</span>.strip()</pre>\n</div>\n<h3>Abstract Base Model (timestamp mixin)</h3>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python</span></div>\n<pre><span>class</span> <span>TimeStampedModel</span>(models.<span>Model</span>):\n <span>\"\"\"Abstract base that adds created_at / updated_at to any model.\"\"\"</span>\n created_at <span>=</span> models.<span>DateTimeField</span>(auto_now_add<span>=</span><span>True</span>)\n updated_at <span>=</span> models.<span>DateTimeField</span>(auto_now<span>=</span><span>True</span>)\n\n <span>class</span> <span>Meta</span>:\n abstract <span>=</span> <span>True</span>\n\n\n<span>class</span> <span>Product</span>(<span>TimeStampedModel</span>):\n name <span>=</span> models.<span>CharField</span>(max_length<span>=</span><span>255</span>)\n slug <span>=</span> models.<span>SlugField</span>(unique<span>=</span><span>True</span>)\n price <span>=</span> models.<span>DecimalField</span>(max_digits<span>=</span><span>10</span>, decimal_places<span>=</span><span>2</span>)\n description <span>=</span> models.<span>TextField</span>(blank<span>=</span><span>True</span>)\n image <span>=</span> models.<span>ImageField</span>(upload_to<span>=</span><span>'products/'</span>, null<span>=</span><span>True</span>)\n is_active <span>=</span> models.<span>BooleanField</span>(default<span>=</span><span>True</span>)\n category <span>=</span> models.<span>ForeignKey</span>(\n <span>'Category'</span>, on_delete<span>=</span>models.<span>PROTECT</span>,\n related_name<span>=</span><span>'products'</span>)\n tags <span>=</span> models.<span>ManyToManyField</span>(<span>'Tag'</span>, blank<span>=</span><span>True</span>)\n\n <span>class</span> <span>Meta</span>:\n ordering <span>=</span> [<span>'-created_at'</span>]\n indexes <span>=</span> [\n models.<span>Index</span>(fields<span>=</span>[<span>'slug'</span>]),\n models.<span>Index</span>(fields<span>=</span>[<span>'is_active'</span>, <span>'-created_at'</span>]),\n ]\n\n <span>def</span> <span>__str__</span>(<span>self</span>):\n <span>return</span> <span>self</span>.name</pre>\n</div>\n<h4>All Field Types</h4>\n<div class=\"table-wrap\">\n<table>\n<tr><th>Field</th><th>Use</th><th>Key Options</th></tr>\n<tr><td>CharField</td><td>Short text</td><td>max_length, blank, choices</td></tr>\n<tr><td>TextField</td><td>Long text</td><td>blank=True</td></tr>\n<tr><td>IntegerField / BigIntegerField</td><td>Integers</td><td>default, null</td></tr>\n<tr><td>FloatField / DecimalField</td><td>Numbers</td><td>max_digits, decimal_places</td></tr>\n<tr><td>BooleanField</td><td>True/False</td><td>default</td></tr>\n<tr><td>DateField / DateTimeField</td><td>Dates</td><td>auto_now, auto_now_add</td></tr>\n<tr><td>EmailField</td><td>Email</td><td>unique</td></tr>\n<tr><td>URLField</td><td>URL</td><td>max_length</td></tr>\n<tr><td>SlugField</td><td>URL slug</td><td>unique, allow_unicode</td></tr>\n<tr><td>UUIDField</td><td>UUID primary key</td><td>default=uuid.uuid4, editable=False</td></tr>\n<tr><td>FileField / ImageField</td><td>Uploads</td><td>upload_to</td></tr>\n<tr><td>JSONField</td><td>JSON data</td><td>default=dict, encoder</td></tr>\n<tr><td>ForeignKey</td><td>Many-to-one</td><td>on_delete, related_name</td></tr>\n<tr><td>ManyToManyField</td><td>Many-to-many</td><td>through, blank</td></tr>\n<tr><td>OneToOneField</td><td>One-to-one</td><td>on_delete, parent_link</td></tr>\n</table>\n</div>\n<h3>Custom Manager</h3>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python</span></div>\n<pre><span>class</span> <span>ActiveManager</span>(models.<span>Manager</span>):\n <span>def</span> <span>get_queryset</span>(<span>self</span>):\n <span>return</span> <span>super</span>().<span>get_queryset</span>().filter(is_active<span>=</span><span>True</span>)\n\n <span>def</span> <span>published</span>(<span>self</span>):\n <span>return</span> <span>self</span>.<span>get_queryset</span>().filter(status<span>=</span><span>'published'</span>)\n\n\n<span>class</span> <span>Article</span>(models.<span>Model</span>):\n objects <span>=</span> models.<span>Manager</span>() <span># default</span>\n active <span>=</span> <span>ActiveManager</span>() <span># Article.active.all()</span></pre>\n</div>\n</section>\n<section id=\"querysets\">\n<div class=\"section-header\">\n<span class=\"section-num\">05</span>\n<h2>QuerySets &amp; ORM</h2>\n</div>\n<h3>Core QuerySet Methods</h3>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python</span></div>\n<pre><span>from</span> django.db.models <span>import</span> Q, F, Count, Sum, Avg, Max, Min, Prefetch\n\n<span># Retrieval</span>\nProduct.objects.<span>all</span>()\nProduct.objects.<span>filter</span>(is_active<span>=</span><span>True</span>, price__lt<span>=</span><span>100</span>)\nProduct.objects.<span>exclude</span>(category__name<span>=</span><span>'archived'</span>)\nProduct.objects.<span>get</span>(slug<span>=</span><span>'my-product'</span>) <span># raises if 0 or 2+</span>\nProduct.objects.<span>get_or_create</span>(slug<span>=</span><span>'x'</span>, defaults<span>=</span>{<span>'name'</span>:<span>'X'</span>})\nProduct.objects.<span>update_or_create</span>(slug<span>=</span><span>'x'</span>, defaults<span>=</span>{...})\nProduct.objects.<span>first</span>() <span># last()</span>\nProduct.objects.<span>exists</span>()\n\n<span># Field lookups</span>\n.<span>filter</span>(name__icontains<span>=</span><span>'phone'</span>) <span># case-insensitive</span>\n.<span>filter</span>(created_at__date<span>=</span><span>'2024-01-01'</span>)\n.<span>filter</span>(price__range<span>=</span>(<span>10</span>, <span>100</span>))\n.<span>filter</span>(tags__isnull<span>=</span><span>False</span>)\n.<span>filter</span>(slug__in<span>=</span>[<span>'a'</span>, <span>'b'</span>, <span>'c'</span>])\n\n<span># Q objects \u2014 complex OR/AND/NOT queries</span>\nProduct.objects.<span>filter</span>(\n <span>Q</span>(price__lt<span>=</span><span>50</span>) | <span>Q</span>(is_featured<span>=</span><span>True</span>)\n)\n\n<span># F expressions \u2014 reference another field in the same row</span>\nProduct.objects.<span>filter</span>(sale_price__lt<span>=</span><span>F</span>(<span>'price'</span>))\nProduct.objects.<span>update</span>(views<span>=</span><span>F</span>(<span>'views'</span>) <span>+</span> <span>1</span>)\n\n<span># Ordering, slicing</span>\n.<span>order_by</span>(<span>'-created_at'</span>, <span>'name'</span>)\n.<span>values</span>(<span>'id'</span>, <span>'name'</span>) <span># returns dicts</span>\n.<span>values_list</span>(<span>'id'</span>, flat<span>=</span><span>True</span>) <span># returns list of ids</span>\nqs[:<span>10</span>] <span># LIMIT 10</span>\nqs[<span>10</span>:<span>20</span>] <span># LIMIT 10 OFFSET 10</span>\n\n<span># Aggregation</span>\n<span>from</span> django.db.models <span>import</span> Count, Sum\nProduct.objects.<span>aggregate</span>(\n total<span>=</span><span>Count</span>(<span>'id'</span>),\n revenue<span>=</span><span>Sum</span>(<span>'price'</span>)\n)\nCategory.objects.<span>annotate</span>(product_count<span>=</span><span>Count</span>(<span>'products'</span>))\n\n<span># Eager loading \u2014 eliminates N+1 queries</span>\nProduct.objects.<span>select_related</span>(<span>'category'</span>) <span># FK / O2O \u2192 JOIN</span>\nProduct.objects.<span>prefetch_related</span>(<span>'tags'</span>) <span># M2M \u2192 extra query</span>\nProduct.objects.<span>prefetch_related</span>(\n <span>Prefetch</span>(<span>'reviews'</span>, queryset<span>=</span>Review.objects.<span>filter</span>(approved<span>=</span><span>True</span>))\n)\n\n<span># Bulk operations</span>\nProduct.objects.<span>bulk_create</span>([...], batch_size<span>=</span><span>1000</span>)\nProduct.objects.<span>bulk_update</span>(products, [<span>'price'</span>, <span>'name'</span>])\n\n<span># Transactions</span>\n<span>from</span> django.db <span>import</span> transaction\n\n<span>@transaction.atomic</span>\n<span>def</span> <span>transfer_stock</span>(from_id, to_id, qty):\n src <span>=</span> Product.objects.<span>select_for_update</span>().<span>get</span>(pk<span>=</span>from_id)\n dst <span>=</span> Product.objects.<span>select_for_update</span>().<span>get</span>(pk<span>=</span>to_id)\n src.stock <span>-=</span> qty\n dst.stock <span>+=</span> qty\n src.<span>save</span>()\n dst.<span>save</span>()</pre>\n</div>\n<div class=\"callout tone-danger\">\n<span class=\"callout-icon\"></span>\n<div class=\"callout-body\">\n<strong>N+1 Trap</strong>\n Calling <code>product.category.name</code> inside a loop without <code>select_related</code> fires one SQL query per row. Always profile with <code>django-debug-toolbar</code>.\n </div>\n</div>\n</section>\n<section id=\"views\">\n<div class=\"section-header\">\n<span class=\"section-num\">06</span>\n<h2>Views</h2>\n</div>\n<h3>Function-Based Views (FBV)</h3>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python</span></div>\n<pre><span>from</span> django.shortcuts <span>import</span> render, get_object_or_404, redirect\n<span>from</span> django.contrib.auth.decorators <span>import</span> login_required\n<span>from</span> django.views.decorators.http <span>import</span> require_POST, require_GET\n\n<span>@login_required</span>\n<span>@require_GET</span>\n<span>def</span> <span>product_list</span>(request):\n products <span>=</span> Product.objects.<span>filter</span>(is_active<span>=</span><span>True</span>)\n <span>return</span> <span>render</span>(request, <span>'products/list.html'</span>, {<span>'products'</span>: products})\n\n<span>def</span> <span>product_detail</span>(request, slug):\n product <span>=</span> <span>get_object_or_404</span>(Product, slug<span>=</span>slug, is_active<span>=</span><span>True</span>)\n <span>return</span> <span>render</span>(request, <span>'products/detail.html'</span>, {<span>'product'</span>: product})\n\n<span>@login_required</span>\n<span>@require_POST</span>\n<span>def</span> <span>product_delete</span>(request, pk):\n product <span>=</span> <span>get_object_or_404</span>(Product, pk<span>=</span>pk, user<span>=</span>request.user)\n product.<span>delete</span>()\n <span>return</span> <span>redirect</span>(<span>'products:list'</span>)</pre>\n</div>\n<h3>Class-Based Views (CBV)</h3>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python</span></div>\n<pre><span>from</span> django.views.generic <span>import</span> (\n View, TemplateView, ListView, DetailView,\n CreateView, UpdateView, DeleteView\n)\n<span>from</span> django.contrib.auth.mixins <span>import</span> LoginRequiredMixin, PermissionRequiredMixin\n<span>from</span> django.urls <span>import</span> reverse_lazy\n\n<span>class</span> <span>ProductListView</span>(LoginRequiredMixin, ListView):\n model <span>=</span> Product\n template_name <span>=</span> <span>'products/list.html'</span>\n context_object_name <span>=</span> <span>'products'</span>\n paginate_by <span>=</span> <span>20</span>\n\n <span>def</span> <span>get_queryset</span>(<span>self</span>):\n qs <span>=</span> <span>super</span>().<span>get_queryset</span>().<span>filter</span>(is_active<span>=</span><span>True</span>)\n q <span>=</span> <span>self</span>.request.GET.<span>get</span>(<span>'q'</span>)\n <span>if</span> q:\n qs <span>=</span> qs.<span>filter</span>(name__icontains<span>=</span>q)\n <span>return</span> qs\n\n <span>def</span> <span>get_context_data</span>(<span>self</span>, <span>**</span>kwargs):\n ctx <span>=</span> <span>super</span>().<span>get_context_data</span>(<span>**</span>kwargs)\n ctx[<span>'total'</span>] <span>=</span> <span>self</span>.<span>get_queryset</span>().<span>count</span>()\n <span>return</span> ctx\n\n\n<span>class</span> <span>ProductCreateView</span>(LoginRequiredMixin, CreateView):\n model <span>=</span> Product\n fields <span>=</span> [<span>'name'</span>, <span>'price'</span>, <span>'description'</span>]\n success_url <span>=</span> reverse_lazy(<span>'products:list'</span>)\n\n <span>def</span> <span>form_valid</span>(<span>self</span>, form):\n form.instance.owner <span>=</span> <span>self</span>.request.user\n <span>return</span> <span>super</span>().<span>form_valid</span>(form)\n\n\n<span>class</span> <span>ProductDeleteView</span>(LoginRequiredMixin, DeleteView):\n model <span>=</span> Product\n success_url <span>=</span> reverse_lazy(<span>'products:list'</span>)\n\n <span>def</span> <span>get_queryset</span>(<span>self</span>): <span># only owner can delete</span>\n <span>return</span> <span>super</span>().<span>get_queryset</span>().<span>filter</span>(owner<span>=</span><span>self</span>.request.user)</pre>\n</div>\n<h4>CBV Cheat Sheet</h4>\n<div class=\"table-wrap\">\n<table>\n<tr><th>Class</th><th>HTTP</th><th>Method to override</th></tr>\n<tr><td>TemplateView</td><td>GET</td><td>get_context_data</td></tr>\n<tr><td>ListView</td><td>GET</td><td>get_queryset, get_context_data</td></tr>\n<tr><td>DetailView</td><td>GET</td><td>get_object, get_context_data</td></tr>\n<tr><td>CreateView</td><td>GET/POST</td><td>form_valid, get_form</td></tr>\n<tr><td>UpdateView</td><td>GET/POST</td><td>form_valid, get_object</td></tr>\n<tr><td>DeleteView</td><td>GET/POST</td><td>get_object, get_success_url</td></tr>\n<tr><td>FormView</td><td>GET/POST</td><td>form_valid, form_invalid</td></tr>\n</table>\n</div>\n</section>\n<section id=\"urls\">\n<div class=\"section-header\">\n<span class=\"section-num\">07</span>\n<h2>URL Configuration</h2>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python \u00b7 config/urls.py</span></div>\n<pre><span>from</span> django.contrib <span>import</span> admin\n<span>from</span> django.urls <span>import</span> path, include\n<span>from</span> django.conf <span>import</span> settings\n<span>from</span> django.conf.urls.static <span>import</span> static\n\nurlpatterns <span>=</span> [\n path(<span>'admin/'</span>, admin.site.urls),\n path(<span>'api/v1/'</span>, include(<span>'apps.api.urls'</span>)),\n path(<span>''</span>, include(<span>'apps.core.urls'</span>)),\n] <span>+</span> static(settings.MEDIA_URL, document_root<span>=</span>settings.MEDIA_ROOT)\n\n<span># apps/products/urls.py</span>\napp_name <span>=</span> <span>'products'</span>\n\nurlpatterns <span>=</span> [\n path(<span>''</span>, <span>ProductListView</span>.<span>as_view</span>(), name<span>=</span><span>'list'</span>),\n path(<span>'&lt;slug:slug&gt;/'</span>, <span>ProductDetailView</span>.<span>as_view</span>(), name<span>=</span><span>'detail'</span>),\n path(<span>'new/'</span>, <span>ProductCreateView</span>.<span>as_view</span>(), name<span>=</span><span>'create'</span>),\n path(<span>'&lt;int:pk&gt;/edit/'</span>, <span>ProductUpdateView</span>.<span>as_view</span>(), name<span>=</span><span>'update'</span>),\n\n <span># URL converters: str, int, slug, uuid, path</span>\n path(<span>'&lt;uuid:uid&gt;/'</span>, <span>SomeView</span>.<span>as_view</span>()),\n]</pre>\n</div>\n</section>\n<section id=\"templates\">\n<div class=\"section-header\">\n<span class=\"section-num\">08</span>\n<h2>Templates</h2>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">html \u00b7 templates/base.html</span></div>\n<pre><span>{# base.html #}</span>\n&lt;!DOCTYPE html&gt;\n&lt;html&gt;\n&lt;head&gt;\n &lt;title&gt;{% block title %}Site{% endblock %}&lt;/title&gt;\n {% load static %}\n &lt;link rel=\"stylesheet\" href=\"{% static 'css/main.css' %}\"&gt;\n&lt;/head&gt;\n&lt;body&gt;\n {% include \"partials/_nav.html\" %}\n\n {% if messages %}\n {% for message in messages %}\n &lt;div class=\"alert alert-{{ message.tags }}\"&gt;{{ message }}&lt;/div&gt;\n {% endfor %}\n {% endif %}\n\n &lt;main&gt;{% block content %}{% endblock %}&lt;/main&gt;\n\n {% block scripts %}{% endblock %}\n&lt;/body&gt;\n&lt;/html&gt;\n\n<span>{# child template #}</span>\n{% extends \"base.html\" %}\n{% block title %}Products{% endblock %}\n{% block content %}\n {% for product in products %}\n &lt;p&gt;{{ product.name }} \u2014 {{ product.price|floatformat:2 }}&lt;/p&gt;\n {% empty %}\n &lt;p&gt;No products found.&lt;/p&gt;\n {% endfor %}\n\n <span>{# pagination #}</span>\n {% if is_paginated %}\n {% if page_obj.has_previous %}\n &lt;a href=\"?page={{ page_obj.previous_page_number }}\"&gt;Prev&lt;/a&gt;\n {% endif %}\n Page {{ page_obj.number }} of {{ page_obj.paginator.num_pages }}\n {% if page_obj.has_next %}\n &lt;a href=\"?page={{ page_obj.next_page_number }}\"&gt;Next&lt;/a&gt;\n {% endif %}\n {% endif %}\n{% endblock %}</pre>\n</div>\n<h4>Built-in Template Filters</h4>\n<div class=\"table-wrap\">\n<table>\n<tr><th>Filter</th><th>Example</th><th>Output</th></tr>\n<tr><td>date</td><td>{{ dt|date:\"Y-m-d\" }}</td><td>2024-06-01</td></tr>\n<tr><td>truncatewords</td><td>{{ text|truncatewords:20 }}</td><td>first 20 words\u2026</td></tr>\n<tr><td>floatformat</td><td>{{ price|floatformat:2 }}</td><td>9.99</td></tr>\n<tr><td>default</td><td>{{ val|default:\"N/A\" }}</td><td>N/A if falsy</td></tr>\n<tr><td>linebreaksbr</td><td>{{ text|linebreaksbr }}</td><td>newlines \u2192 &lt;br&gt;</td></tr>\n<tr><td>slugify</td><td>{{ name|slugify }}</td><td>my-product</td></tr>\n<tr><td>safe</td><td>{{ html|safe }}</td><td>renders raw HTML</td></tr>\n<tr><td>length</td><td>{{ list|length }}</td><td>integer count</td></tr>\n<tr><td>urlencode</td><td>{{ param|urlencode }}</td><td>URL-safe string</td></tr>\n<tr><td>join</td><td>{{ list|join:\", \" }}</td><td>a, b, c</td></tr>\n</table>\n</div>\n<h3>Custom Template Tag</h3>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python \u00b7 templatetags/product_tags.py</span></div>\n<pre><span>from</span> django <span>import</span> template\nregister <span>=</span> template.<span>Library</span>()\n\n<span>@register.filter</span>\n<span>def</span> <span>currency</span>(value, symbol<span>=</span><span>'\u20ac'</span>):\n <span>return</span> <span>f'<span>{</span>symbol<span>}</span><span>{</span>value:.2f<span>}</span>'</span>\n\n<span>@register.simple_tag</span>(takes_context<span>=</span><span>True</span>)\n<span>def</span> <span>active_link</span>(context, url_name):\n request <span>=</span> context[<span>'request'</span>]\n <span>from</span> django.urls <span>import</span> reverse\n <span>return</span> <span>'active'</span> <span>if</span> request.path <span>==</span> <span>reverse</span>(url_name) <span>else</span> <span>''</span>\n\n<span>@register.inclusion_tag</span>(<span>'partials/_featured.html'</span>)\n<span>def</span> <span>featured_products</span>(count<span>=</span><span>4</span>):\n <span>return</span> {<span>'products'</span>: Product.objects.<span>filter</span>(is_featured<span>=</span><span>True</span>)[:<span>count</span>]}</pre>\n</div>\n</section>\n<section id=\"forms\">\n<div class=\"section-header\">\n<span class=\"section-num\">09</span>\n<h2>Forms</h2>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python \u00b7 forms.py</span></div>\n<pre><span>from</span> django <span>import</span> forms\n<span>from</span> django.core.exceptions <span>import</span> ValidationError\n\n<span>class</span> <span>ProductForm</span>(forms.<span>ModelForm</span>):\n <span>class</span> <span>Meta</span>:\n model <span>=</span> Product\n fields <span>=</span> [<span>'name'</span>, <span>'price'</span>, <span>'description'</span>, <span>'category'</span>]\n widgets <span>=</span> {\n <span>'description'</span>: forms.<span>Textarea</span>(attrs<span>=</span>{<span>'rows'</span>: <span>4</span>}),\n <span>'price'</span>: forms.<span>NumberInput</span>(attrs<span>=</span>{<span>'step'</span>: <span>'0.01'</span>}),\n }\n\n <span>def</span> <span>clean_price</span>(<span>self</span>):\n price <span>=</span> <span>self</span>.cleaned_data[<span>'price'</span>]\n <span>if</span> price <span>&lt;=</span> <span>0</span>:\n <span>raise</span> <span>ValidationError</span>(<span>'Price must be positive.'</span>)\n <span>return</span> price\n\n <span>def</span> <span>clean</span>(<span>self</span>): <span># cross-field validation</span>\n data <span>=</span> <span>super</span>().<span>clean</span>()\n <span>if</span> data.get(<span>'sale_price'</span>) <span>&gt;</span> data.get(<span>'price'</span>, <span>0</span>):\n <span>raise</span> <span>ValidationError</span>(<span>'Sale price must be less than price.'</span>)\n <span>return</span> data</pre>\n</div>\n</section>\n<section id=\"auth\">\n<div class=\"section-header\">\n<span class=\"section-num\">10</span>\n<h2>Authentication</h2>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python</span></div>\n<pre><span>from</span> django.contrib.auth <span>import</span> authenticate, login, logout\n<span>from</span> django.contrib.auth.decorators <span>import</span> login_required, permission_required\n<span>from</span> django.contrib.auth.mixins <span>import</span> (\n LoginRequiredMixin, PermissionRequiredMixin, UserPassesTestMixin\n)\n\n<span># Decorator usage</span>\n<span>@login_required</span>(login_url<span>=</span><span>'/login/'</span>)\n<span>@permission_required</span>(<span>'products.add_product'</span>, raise_exception<span>=</span><span>True</span>)\n<span>def</span> <span>my_view</span>(request): ...\n\n<span># UserPassesTestMixin \u2014 custom logic</span>\n<span>class</span> <span>OwnerOnlyView</span>(UserPassesTestMixin, UpdateView):\n <span>def</span> <span>test_func</span>(<span>self</span>):\n <span>return</span> <span>self</span>.<span>get_object</span>().owner <span>==</span> <span>self</span>.request.user\n\n<span># Login / logout</span>\n<span>def</span> <span>login_view</span>(request):\n <span>if</span> request.method <span>==</span> <span>'POST'</span>:\n user <span>=</span> <span>authenticate</span>(\n request,\n username<span>=</span>request.POST[<span>'email'</span>],\n password<span>=</span>request.POST[<span>'password'</span>]\n )\n <span>if</span> user:\n <span>login</span>(request, user)\n <span>return</span> <span>redirect</span>(<span>'dashboard'</span>)\n <span>return</span> <span>render</span>(request, <span>'auth/login.html'</span>)\n\n<span># Password reset \u2014 built-in views</span>\n<span>from</span> django.contrib.auth <span>import</span> views <span>as</span> auth_views\npath(<span>'password/reset/'</span>, auth_views.<span>PasswordResetView</span>.<span>as_view</span>(), name<span>=</span><span>'password_reset'</span>)</pre>\n</div>\n</section>\n<section id=\"middleware\">\n<div class=\"section-header\">\n<span class=\"section-num\">11</span>\n<h2>Middleware</h2>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python \u00b7 middleware.py</span></div>\n<pre><span>import</span> time\n<span>import</span> logging\nlogger <span>=</span> logging.<span>getLogger</span>(<span>__name__</span>)\n\n<span>class</span> <span>RequestTimingMiddleware</span>:\n <span>\"\"\"Log slow requests &gt; 500 ms.\"\"\"</span>\n <span>def</span> <span>__init__</span>(<span>self</span>, get_response):\n <span>self</span>.get_response <span>=</span> get_response\n\n <span>def</span> <span>__call__</span>(<span>self</span>, request):\n start <span>=</span> time.<span>monotonic</span>()\n response <span>=</span> <span>self</span>.<span>get_response</span>(request)\n duration <span>=</span> time.<span>monotonic</span>() <span>-</span> start\n <span>if</span> duration <span>&gt;</span> <span>0.5</span>:\n logger.<span>warning</span>(<span>f'Slow request: <span>{</span>request.path<span>}</span> took <span>{</span>duration:.2f<span>}</span>s'</span>)\n <span>return</span> response\n\n<span># Add to MIDDLEWARE list in settings</span>\nMIDDLEWARE <span>=</span> [\n <span>'django.middleware.security.SecurityMiddleware'</span>,\n <span>'corsheaders.middleware.CorsMiddleware'</span>, <span># must be first</span>\n <span>'django.contrib.sessions.middleware.SessionMiddleware'</span>,\n <span>'django.middleware.common.CommonMiddleware'</span>,\n <span>'django.middleware.csrf.CsrfViewMiddleware'</span>,\n <span>'django.contrib.auth.middleware.AuthenticationMiddleware'</span>,\n <span>'django.contrib.messages.middleware.MessageMiddleware'</span>,\n <span>'myapp.middleware.RequestTimingMiddleware'</span>,\n]</pre>\n</div>\n</section>\n<section id=\"signals\">\n<div class=\"section-header\">\n<span class=\"section-num\">12</span>\n<h2>Signals</h2>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python \u00b7 signals.py</span></div>\n<pre><span>from</span> django.db.models.signals <span>import</span> post_save, pre_delete, m2m_changed\n<span>from</span> django.dispatch <span>import</span> receiver, Signal\n<span>from</span> django.utils.text <span>import</span> slugify\n\n<span>@receiver</span>(post_save, sender<span>=</span>Product)\n<span>def</span> <span>auto_slug</span>(sender, instance, created, <span>**</span>kwargs):\n <span>if</span> created <span>and not</span> instance.slug:\n instance.slug <span>=</span> <span>slugify</span>(instance.name)\n instance.<span>save</span>(update_fields<span>=</span>[<span>'slug'</span>])\n\n<span>@receiver</span>(post_save, sender<span>=</span>User)\n<span>def</span> <span>create_profile</span>(sender, instance, created, <span>**</span>kwargs):\n <span>if</span> created:\n Profile.objects.<span>create</span>(user<span>=</span>instance)\n\n<span># Custom signal</span>\norder_shipped <span>=</span> <span>Signal</span>()\n\n<span>def</span> <span>ship_order</span>(order):\n <span># \u2026shipping logic\u2026</span>\n order_shipped.<span>send</span>(sender<span>=</span>Order, instance<span>=</span>order)\n\n<span>@receiver</span>(order_shipped)\n<span>def</span> <span>send_confirmation_email</span>(sender, instance, <span>**</span>kwargs):\n send_mail(<span>'Shipped!'</span>, <span>'...'</span>, <span>'noreply@shop.com'</span>, [instance.user.email])\n\n<span># Connect in AppConfig.ready() \u2014 apps/products/apps.py</span>\n<span>class</span> <span>ProductsConfig</span>(AppConfig):\n name <span>=</span> <span>'apps.products'</span>\n <span>def</span> <span>ready</span>(<span>self</span>):\n <span>import</span> apps.products.signals <span># noqa</span></pre>\n</div>\n<div class=\"callout tone-danger\">\n<span class=\"callout-icon\"></span>\n<div class=\"callout-body\">\n<strong>Avoid save loops</strong>\n When calling <code>.save()</code> inside a <code>post_save</code> signal, always use <code>update_fields</code> to limit the fields updated \u2014 otherwise you trigger infinite recursion.\n </div>\n</div>\n</section>\n<section id=\"admin\">\n<div class=\"section-header\">\n<span class=\"section-num\">13</span>\n<h2>Admin</h2>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python \u00b7 admin.py</span></div>\n<pre><span>from</span> django.contrib <span>import</span> admin\n<span>from</span> django.utils.html <span>import</span> format_html\n\n<span>@admin.register</span>(Product)\n<span>class</span> <span>ProductAdmin</span>(admin.<span>ModelAdmin</span>):\n list_display <span>=</span> [<span>'name'</span>, <span>'price'</span>, <span>'category'</span>, <span>'is_active'</span>, <span>'preview'</span>]\n list_filter <span>=</span> [<span>'is_active'</span>, <span>'category'</span>, <span>'created_at'</span>]\n search_fields <span>=</span> [<span>'name'</span>, <span>'description'</span>]\n prepopulated_fields <span>=</span> {<span>'slug'</span>: [<span>'name'</span>]}\n list_editable <span>=</span> [<span>'is_active'</span>]\n list_per_page <span>=</span> <span>50</span>\n date_hierarchy <span>=</span> <span>'created_at'</span>\n readonly_fields <span>=</span> [<span>'created_at'</span>, <span>'updated_at'</span>]\n\n fieldsets <span>=</span> [\n (<span>None</span>, {<span>'fields'</span>: [<span>'name'</span>, <span>'slug'</span>, <span>'category'</span>]}),\n (<span>'Pricing'</span>, {<span>'fields'</span>: [<span>'price'</span>, <span>'sale_price'</span>]}),\n (<span>'Meta'</span>, {<span>'fields'</span>: [<span>'is_active'</span>, <span>'created_at'</span>, <span>'updated_at'</span>],\n <span>'classes'</span>: [<span>'collapse'</span>]}),\n ]\n\n <span>def</span> <span>preview</span>(<span>self</span>, obj):\n <span>if</span> obj.image:\n <span>return</span> <span>format_html</span>(\n <span>'&lt;img src=\"{}\" width=\"50\" height=\"50\" style=\"object-fit:cover\"&gt;'</span>,\n obj.image.url)\n <span>return</span> <span>'-'</span>\n preview.short_description <span>=</span> <span>'Image'</span>\n\n <span>def</span> <span>get_queryset</span>(<span>self</span>, request):\n <span>return</span> <span>super</span>().<span>get_queryset</span>(request).<span>select_related</span>(<span>'category'</span>)\n\n actions <span>=</span> [<span>'activate'</span>, <span>'deactivate'</span>]\n\n <span>@admin.action</span>(description<span>=</span><span>'Mark selected as active'</span>)\n <span>def</span> <span>activate</span>(<span>self</span>, request, queryset):\n queryset.<span>update</span>(is_active<span>=</span><span>True</span>)</pre>\n</div>\n</section>\n<section id=\"rest\">\n<div class=\"section-header\">\n<span class=\"section-num\">14</span>\n<h2>Django REST Framework</h2>\n</div>\n<h3>Serializers</h3>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python \u00b7 serializers.py</span></div>\n<pre><span>from</span> rest_framework <span>import</span> serializers\n\n<span>class</span> <span>CategorySerializer</span>(serializers.<span>ModelSerializer</span>):\n <span>class</span> <span>Meta</span>:\n model <span>=</span> Category\n fields <span>=</span> [<span>'id'</span>, <span>'name'</span>, <span>'slug'</span>]\n\n<span>class</span> <span>ProductSerializer</span>(serializers.<span>ModelSerializer</span>):\n category <span>=</span> <span>CategorySerializer</span>(read_only<span>=</span><span>True</span>)\n category_id <span>=</span> serializers.<span>PrimaryKeyRelatedField</span>(\n queryset<span>=</span>Category.objects.<span>all</span>(), source<span>=</span><span>'category'</span>, write_only<span>=</span><span>True</span>)\n full_url <span>=</span> serializers.<span>SerializerMethodField</span>()\n\n <span>class</span> <span>Meta</span>:\n model <span>=</span> Product\n fields <span>=</span> [<span>'id'</span>, <span>'name'</span>, <span>'slug'</span>, <span>'price'</span>,\n <span>'category'</span>, <span>'category_id'</span>, <span>'full_url'</span>]\n read_only_fields <span>=</span> [<span>'slug'</span>, <span>'created_at'</span>]\n\n <span>def</span> <span>get_full_url</span>(<span>self</span>, obj):\n request <span>=</span> <span>self</span>.context.<span>get</span>(<span>'request'</span>)\n <span>return</span> request.<span>build_absolute_uri</span>(obj.<span>get_absolute_url</span>())\n\n <span>def</span> <span>validate_price</span>(<span>self</span>, value):\n <span>if</span> value <span>&lt;=</span> <span>0</span>:\n <span>raise</span> serializers.<span>ValidationError</span>(<span>'Must be positive.'</span>)\n <span>return</span> value</pre>\n</div>\n<h3>ViewSets &amp; Routers</h3>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python \u00b7 views.py (API)</span></div>\n<pre><span>from</span> rest_framework <span>import</span> viewsets, permissions, filters, status\n<span>from</span> rest_framework.decorators <span>import</span> action\n<span>from</span> rest_framework.response <span>import</span> Response\n<span>from</span> django_filters.rest_framework <span>import</span> DjangoFilterBackend\n\n<span>class</span> <span>ProductViewSet</span>(viewsets.<span>ModelViewSet</span>):\n queryset <span>=</span> Product.objects.<span>filter</span>(is_active<span>=</span><span>True</span>)\n serializer_class <span>=</span> ProductSerializer\n permission_classes <span>=</span> [permissions.<span>IsAuthenticatedOrReadOnly</span>]\n filter_backends <span>=</span> [DjangoFilterBackend, filters.<span>SearchFilter</span>, filters.<span>OrderingFilter</span>]\n filterset_fields <span>=</span> [<span>'category'</span>, <span>'is_active'</span>]\n search_fields <span>=</span> [<span>'name'</span>, <span>'description'</span>]\n ordering_fields <span>=</span> [<span>'price'</span>, <span>'created_at'</span>]\n\n <span>def</span> <span>get_queryset</span>(<span>self</span>):\n <span>return</span> <span>super</span>().<span>get_queryset</span>().<span>select_related</span>(<span>'category'</span>)\n\n <span>def</span> <span>perform_create</span>(<span>self</span>, serializer):\n serializer.<span>save</span>(owner<span>=</span><span>self</span>.request.user)\n\n <span>@action</span>(detail<span>=</span><span>True</span>, methods<span>=</span>[<span>'post'</span>], permission_classes<span>=</span>[permissions.<span>IsAdminUser</span>])\n <span>def</span> <span>feature</span>(<span>self</span>, request, pk<span>=</span><span>None</span>):\n product <span>=</span> <span>self</span>.<span>get_object</span>()\n product.is_featured <span>=</span> <span>not</span> product.is_featured\n product.<span>save</span>()\n <span>return</span> <span>Response</span>({<span>'featured'</span>: product.is_featured})\n\n<span># urls.py</span>\n<span>from</span> rest_framework.routers <span>import</span> DefaultRouter\nrouter <span>=</span> <span>DefaultRouter</span>()\nrouter.<span>register</span>(<span>'products'</span>, <span>ProductViewSet</span>)\nurlpatterns <span>=</span> router.urls</pre>\n</div>\n<h3>Custom Permissions</h3>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python \u00b7 permissions.py</span></div>\n<pre><span>from</span> rest_framework <span>import</span> permissions\n\n<span>class</span> <span>IsOwnerOrReadOnly</span>(permissions.<span>BasePermission</span>):\n <span>def</span> <span>has_object_permission</span>(<span>self</span>, request, view, obj):\n <span>if</span> request.method <span>in</span> permissions.SAFE_METHODS:\n <span>return</span> <span>True</span>\n <span>return</span> obj.owner <span>==</span> request.user</pre>\n</div>\n<h3>JWT Auth Setup</h3>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python \u00b7 settings.py + urls.py</span></div>\n<pre><span># pip install djangorestframework-simplejwt</span>\nREST_FRAMEWORK <span>=</span> {\n <span>'DEFAULT_AUTHENTICATION_CLASSES'</span>: [\n <span>'rest_framework_simplejwt.authentication.JWTAuthentication'</span>,\n ],\n <span>'DEFAULT_PERMISSION_CLASSES'</span>: [\n <span>'rest_framework.permissions.IsAuthenticated'</span>,\n ],\n <span>'DEFAULT_PAGINATION_CLASS'</span>: <span>'rest_framework.pagination.PageNumberPagination'</span>,\n <span>'PAGE_SIZE'</span>: <span>20</span>,\n <span>'DEFAULT_THROTTLE_CLASSES'</span>: [\n <span>'rest_framework.throttling.AnonRateThrottle'</span>,\n <span>'rest_framework.throttling.UserRateThrottle'</span>,\n ],\n <span>'DEFAULT_THROTTLE_RATES'</span>: {<span>'anon'</span>: <span>'100/day'</span>, <span>'user'</span>: <span>'1000/day'</span>},\n}\n\n<span>from</span> rest_framework_simplejwt.views <span>import</span> TokenObtainPairView, TokenRefreshView\npath(<span>'api/token/'</span>, <span>TokenObtainPairView</span>.<span>as_view</span>()),\npath(<span>'api/token/refresh/'</span>, <span>TokenRefreshView</span>.<span>as_view</span>()),</pre>\n</div>\n</section>\n<section id=\"celery\">\n<div class=\"section-header\">\n<span class=\"section-num\">15</span>\n<h2>Celery &amp; Async Tasks</h2>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python \u00b7 config/celery.py</span></div>\n<pre><span>import</span> os\n<span>from</span> celery <span>import</span> Celery\n\nos.<span>environ</span>.<span>setdefault</span>(<span>'DJANGO_SETTINGS_MODULE'</span>, <span>'config.settings.production'</span>)\n\napp <span>=</span> <span>Celery</span>(<span>'myproject'</span>)\napp.config_from_object(<span>'django.conf:settings'</span>, namespace<span>=</span><span>'CELERY'</span>)\napp.<span>autodiscover_tasks</span>() <span># finds tasks.py in each INSTALLED_APP</span>\n\n<span># settings.py</span>\nCELERY_BROKER_URL <span>=</span> <span>'redis://localhost:6379/0'</span>\nCELERY_RESULT_BACKEND <span>=</span> <span>'redis://localhost:6379/0'</span>\nCELERY_TASK_SERIALIZER <span>=</span> <span>'json'</span>\n\n<span># apps/products/tasks.py</span>\n<span>from</span> celery <span>import</span> shared_task\n<span>from</span> celery.utils.log <span>import</span> get_task_logger\nlogger <span>=</span> <span>get_task_logger</span>(<span>__name__</span>)\n\n<span>@shared_task</span>(bind<span>=</span><span>True</span>, max_retries<span>=</span><span>3</span>, default_retry_delay<span>=</span><span>60</span>)\n<span>def</span> <span>send_welcome_email</span>(<span>self</span>, user_id):\n <span>try</span>:\n user <span>=</span> User.objects.<span>get</span>(pk<span>=</span>user_id)\n <span># send mail\u2026</span>\n logger.<span>info</span>(<span>f'Email sent to <span>{</span>user.email<span>}</span>'</span>)\n <span>except</span> <span>Exception</span> <span>as</span> exc:\n <span>raise</span> <span>self</span>.<span>retry</span>(exc<span>=</span>exc)\n\n<span># Call it</span>\nsend_welcome_email.<span>delay</span>(user_id<span>=</span>user.pk)\nsend_welcome_email.<span>apply_async</span>(args<span>=</span>[user.pk], countdown<span>=</span><span>60</span>)\n\n<span># Periodic tasks (Celery Beat)</span>\n<span>from</span> celery.schedules <span>import</span> crontab\nCELERY_BEAT_SCHEDULE <span>=</span> {\n <span>'clean-expired-sessions'</span>: {\n <span>'task'</span>: <span>'apps.users.tasks.clean_sessions'</span>,\n <span>'schedule'</span>: crontab(hour<span>=</span><span>0</span>, minute<span>=</span><span>0</span>), <span># midnight daily</span>\n },\n}</pre>\n</div>\n</section>\n<section id=\"caching\">\n<div class=\"section-header\">\n<span class=\"section-num\">16</span>\n<h2>Caching</h2>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python</span></div>\n<pre><span># settings.py</span>\nCACHES <span>=</span> {\n <span>'default'</span>: {\n <span>'BACKEND'</span>: <span>'django.core.cache.backends.redis.RedisCache'</span>,\n <span>'LOCATION'</span>: <span>'redis://127.0.0.1:6379/1'</span>,\n }\n}\n\n<span># Low-level cache API</span>\n<span>from</span> django.core.cache <span>import</span> cache\n\ncache.<span>set</span>(<span>'product_count'</span>, <span>42</span>, timeout<span>=</span><span>300</span>) <span># 5 mins</span>\ncount <span>=</span> cache.<span>get</span>(<span>'product_count'</span>)\ncache.<span>delete</span>(<span>'product_count'</span>)\ncache.<span>get_or_set</span>(<span>'key'</span>, <span>lambda</span>: expensive_call(), <span>300</span>)\n\n<span># cache_page decorator</span>\n<span>from</span> django.views.decorators.cache <span>import</span> cache_page\n<span>from</span> django.views.decorators.vary <span>import</span> vary_on_headers\n\n<span>@cache_page</span>(<span>60</span> <span>*</span> <span>15</span>) <span># 15 minutes</span>\n<span>@vary_on_headers</span>(<span>'Accept-Language'</span>)\n<span>def</span> <span>product_list</span>(request): ...\n\n<span># Template fragment caching</span>\n<span># {% load cache %}</span>\n<span># {% cache 300 sidebar request.user.id %}</span>\n<span># \u2026 expensive template fragment \u2026</span>\n<span># {% endcache %}</span>\n\n<span># Django cache_page for CBVs</span>\n<span>from</span> django.utils.decorators <span>import</span> method_decorator\n<span>class</span> <span>ProductListView</span>(ListView):\n <span>@method_decorator</span>(<span>cache_page</span>(<span>60</span><span>*</span><span>5</span>))\n <span>def</span> <span>dispatch</span>(<span>self</span>, <span>*</span>args, <span>**</span>kwargs):\n <span>return</span> <span>super</span>().<span>dispatch</span>(<span>*</span>args, <span>**</span>kwargs)</pre>\n</div>\n</section>\n<section id=\"security\">\n<div class=\"section-header\">\n<span class=\"section-num\">17</span>\n<h2>Security</h2>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python \u00b7 settings/production.py</span></div>\n<pre>DEBUG <span>=</span> <span>False</span>\n\n<span># HTTPS</span>\nSECURE_SSL_REDIRECT <span>=</span> <span>True</span>\nSECURE_HSTS_SECONDS <span>=</span> <span>31536000</span>\nSECURE_HSTS_INCLUDE_SUBDOMAINS <span>=</span> <span>True</span>\nSECURE_HSTS_PRELOAD <span>=</span> <span>True</span>\nSECURE_PROXY_SSL_HEADER <span>=</span> (<span>'HTTP_X_FORWARDED_PROTO'</span>, <span>'https'</span>)\n\n<span># Cookies</span>\nSESSION_COOKIE_SECURE <span>=</span> <span>True</span>\nCSRF_COOKIE_SECURE <span>=</span> <span>True</span>\nSESSION_COOKIE_HTTPONLY<span>=</span> <span>True</span>\nSESSION_COOKIE_AGE <span>=</span> <span>86400</span> <span># 24h</span>\n\n<span># Clickjacking</span>\nX_FRAME_OPTIONS <span>=</span> <span>'DENY'</span>\nSECURE_CONTENT_TYPE_NOSNIFF <span>=</span> <span>True</span>\nSECURE_BROWSER_XSS_FILTER <span>=</span> <span>True</span>\n\n<span># CORS</span>\nCORS_ALLOWED_ORIGINS <span>=</span> [<span>'https://app.example.com'</span>]\nCORS_ALLOW_CREDENTIALS <span>=</span> <span>True</span>\n\n<span># Content Security Policy (pip install django-csp)</span>\nCSP_DEFAULT_SRC <span>=</span> (<span>\"'self'\"</span>,)\nCSP_SCRIPT_SRC <span>=</span> (<span>\"'self'\"</span>,)\nCSP_STYLE_SRC <span>=</span> (<span>\"'self'\"</span>, <span>'fonts.googleapis.com'</span>)\n\n<span># Password validation</span>\nAUTH_PASSWORD_VALIDATORS <span>=</span> [\n {<span>'NAME'</span>: <span>'django.contrib.auth.password_validation.MinimumLengthValidator'</span>,\n <span>'OPTIONS'</span>: {<span>'min_length'</span>: <span>12</span>}},\n {<span>'NAME'</span>: <span>'django.contrib.auth.password_validation.CommonPasswordValidator'</span>},\n {<span>'NAME'</span>: <span>'django.contrib.auth.password_validation.NumericPasswordValidator'</span>},\n]</pre>\n</div>\n</section>\n<section id=\"performance\">\n<div class=\"section-header\">\n<span class=\"section-num\">18</span>\n<h2>Performance</h2>\n</div>\n<div>\n<div class=\"card\">\n<div class=\"card-title\">Database indexes</div>\n<div class=\"card-desc\">Add <code>Meta.indexes</code> on fields used in <code>filter()</code>, <code>order_by()</code>, and JOINs. Use <code>db_index=True</code> on FK fields when needed.</div>\n</div>\n<div class=\"card\">\n<div class=\"card-title\">select_related / prefetch_related</div>\n<div class=\"card-desc\">Eliminate N+1 queries. Run <code>django-debug-toolbar</code> in dev to detect them at a glance.</div>\n</div>\n<div class=\"card\">\n<div class=\"card-title\">only() / defer()</div>\n<div class=\"card-desc\">Load only the columns you need. <code>.only('id','name')</code> avoids fetching large text fields.</div>\n</div>\n<div class=\"card\">\n<div class=\"card-title\">Connection pooling</div>\n<div class=\"card-desc\">Use <code>pgBouncer</code> or <code>CONN_MAX_AGE</code> in settings to reuse DB connections.</div>\n</div>\n<div class=\"card\">\n<div class=\"card-title\">Async views (Django 4.1+)</div>\n<div class=\"card-desc\">Define views with <code>async def</code> for I/O-bound tasks. Use <code>sync_to_async</code> wrappers for ORM calls.</div>\n</div>\n<div class=\"card\">\n<div class=\"card-title\">Whitenoise</div>\n<div class=\"card-desc\">Serve static files directly from Django in production with zero Nginx config. Gzip + caching headers built-in.</div>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python \u2014 async view example</span></div>\n<pre><span>from</span> django.http <span>import</span> JsonResponse\n<span>from</span> asgiref.sync <span>import</span> sync_to_async\n\n<span>async def</span> <span>product_api</span>(request, pk):\n product <span>=</span> <span>await</span> sync_to_async(Product.objects.get)(pk<span>=</span>pk)\n <span>return</span> <span>JsonResponse</span>({<span>'name'</span>: product.name, <span>'price'</span>: <span>str</span>(product.price)})</pre>\n</div>\n</section>\n<section id=\"testing\">\n<div class=\"section-header\">\n<span class=\"section-num\">19</span>\n<h2>Testing</h2>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python \u00b7 tests/test_products.py</span></div>\n<pre><span>from</span> django.test <span>import</span> TestCase, Client\n<span>from</span> django.urls <span>import</span> reverse\n<span>from</span> django.contrib.auth <span>import</span> get_user_model\n<span>from</span> rest_framework.test <span>import</span> APITestCase, APIClient\n<span>from</span> rest_framework <span>import</span> status\n<span>import</span> factory <span># pip install factory-boy</span>\n\nUser <span>=</span> <span>get_user_model</span>()\n\n<span># Factories \u2014 generate test data</span>\n<span>class</span> <span>UserFactory</span>(factory.<span>django.DjangoModelFactory</span>):\n <span>class</span> <span>Meta</span>:\n model <span>=</span> User\n email <span>=</span> factory.<span>Faker</span>(<span>'email'</span>)\n password <span>=</span> factory.<span>PostGenerationMethodCall</span>(<span>'set_password'</span>, <span>'testpass123'</span>)\n\n<span>class</span> <span>ProductFactory</span>(factory.<span>django.DjangoModelFactory</span>):\n <span>class</span> <span>Meta</span>:\n model <span>=</span> Product\n name <span>=</span> factory.<span>Sequence</span>(<span>lambda</span> n: <span>f'Product <span>{</span>n<span>}</span>'</span>)\n price <span>=</span> factory.<span>Faker</span>(<span>'pydecimal'</span>, left_digits<span>=</span><span>3</span>, right_digits<span>=</span><span>2</span>, positive<span>=</span><span>True</span>)\n owner <span>=</span> factory.<span>SubFactory</span>(<span>UserFactory</span>)\n\n<span>class</span> <span>ProductAPITest</span>(APITestCase):\n <span>def</span> <span>setUp</span>(<span>self</span>):\n <span>self</span>.user <span>=</span> <span>UserFactory</span>()\n <span>self</span>.product <span>=</span> <span>ProductFactory</span>(owner<span>=</span><span>self</span>.user)\n <span>self</span>.client.<span>force_authenticate</span>(user<span>=</span><span>self</span>.user)\n\n <span>def</span> <span>test_list_products</span>(<span>self</span>):\n url <span>=</span> <span>reverse</span>(<span>'product-list'</span>)\n res <span>=</span> <span>self</span>.client.<span>get</span>(url)\n <span>self</span>.<span>assertEqual</span>(res.status_code, status.<span>HTTP_200_OK</span>)\n <span>self</span>.<span>assertGreater</span>(<span>len</span>(res.data[<span>'results'</span>]), <span>0</span>)\n\n <span>def</span> <span>test_create_product_requires_auth</span>(<span>self</span>):\n <span>self</span>.client.<span>logout</span>()\n url <span>=</span> <span>reverse</span>(<span>'product-list'</span>)\n res <span>=</span> <span>self</span>.client.<span>post</span>(url, {})\n <span>self</span>.<span>assertEqual</span>(res.status_code, status.<span>HTTP_401_UNAUTHORIZED</span>)\n\n<span># Run</span>\n<span># python manage.py test</span>\n<span># pytest --cov=apps --cov-report=html</span></pre>\n</div>\n</section>\n<section id=\"commands\">\n<div class=\"section-header\">\n<span class=\"section-num\">20</span>\n<h2>Management Commands</h2>\n</div>\n<h3>Custom Command</h3>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python \u00b7 management/commands/seed_products.py</span></div>\n<pre><span>from</span> django.core.management.base <span>import</span> BaseCommand\n\n<span>class</span> <span>Command</span>(<span>BaseCommand</span>):\n help <span>=</span> <span>'Seed the database with sample products'</span>\n\n <span>def</span> <span>add_arguments</span>(<span>self</span>, parser):\n parser.<span>add_argument</span>(<span>'count'</span>, <span>type</span><span>=</span>int, default<span>=</span><span>10</span>, nargs<span>=</span><span>'?'</span>)\n parser.<span>add_argument</span>(<span>'--clear'</span>, action<span>=</span><span>'store_true'</span>)\n\n <span>def</span> <span>handle</span>(<span>self</span>, <span>*</span>args, <span>**</span>options):\n <span>if</span> options[<span>'clear'</span>]:\n Product.objects.<span>all</span>().<span>delete</span>()\n <span>self</span>.<span>stdout.write</span>(<span>self</span>.style.<span>WARNING</span>(<span>'Cleared existing products.'</span>))\n <span>for</span> i <span>in</span> <span>range</span>(options[<span>'count'</span>]):\n Product.objects.<span>create</span>(name<span>=</span><span>f'Product {i}'</span>, price<span>=</span><span>9.99</span><span>*</span>i)\n <span>self</span>.stdout.<span>write</span>(<span>self</span>.style.<span>SUCCESS</span>(<span>f'Created <span>{</span>options[<span>\"count\"</span>]<span>}</span> products'</span>))\n\n<span># Usage</span>\n<span># python manage.py seed_products 50 --clear</span></pre>\n</div>\n<h4>Essential Built-in Commands</h4>\n<div class=\"table-wrap\">\n<table>\n<tr><th>Command</th><th>Description</th></tr>\n<tr><td>makemigrations</td><td>Generate migration files from model changes</td></tr>\n<tr><td>migrate</td><td>Apply pending migrations to DB</td></tr>\n<tr><td>showmigrations</td><td>Show all migrations and their status</td></tr>\n<tr><td>sqlmigrate app 0001</td><td>Print SQL for a specific migration</td></tr>\n<tr><td>createsuperuser</td><td>Create an admin user interactively</td></tr>\n<tr><td>shell_plus</td><td>Enhanced shell with auto-imports (django-extensions)</td></tr>\n<tr><td>collectstatic</td><td>Gather static files into STATIC_ROOT</td></tr>\n<tr><td>check --deploy</td><td>Run deployment security checklist</td></tr>\n<tr><td>dbshell</td><td>Open database CLI directly</td></tr>\n<tr><td>dumpdata / loaddata</td><td>Export / import fixtures as JSON</td></tr>\n</table>\n</div>\n</section>\n<section id=\"tips\">\n<div class=\"section-header\">\n<span class=\"section-num\">21</span>\n<h2>Tips &amp; Tricks</h2>\n</div>\n<div class=\"callout tone-tip\">\n<span class=\"callout-icon\"></span>\n<div class=\"callout-body\">\n<strong>Use UUID primary keys</strong>\n Replace integer PKs with <code>UUIDField(primary_key=True, default=uuid.uuid4, editable=False)</code>. Prevents sequential-ID enumeration attacks and simplifies distributed systems.\n </div>\n</div>\n<div class=\"callout tone-tip\">\n<span class=\"callout-icon\"></span>\n<div class=\"callout-body\">\n<strong>never use save() to update one field</strong>\n Use <code>Product.objects.filter(pk=pk).update(price=99)</code> or <code>instance.save(update_fields=['price'])</code> \u2014 both avoid race conditions and skip unnecessary signals.\n </div>\n</div>\n<div class=\"callout tone-tip\">\n<span class=\"callout-icon\"></span>\n<div class=\"callout-body\">\n<strong>Annotate don't loop</strong>\n Instead of looping to count related objects, use <code>.annotate(review_count=Count('reviews'))</code>. One query beats 1000.\n </div>\n</div>\n<div class=\"callout tone-danger\">\n<span class=\"callout-icon\"></span>\n<div class=\"callout-body\">\n<strong>NEVER store secrets in settings.py</strong>\n Use <code>django-environ</code> or <code>python-decouple</code>. Add <code>.env</code> to <code>.gitignore</code> from day one.\n </div>\n</div>\n<div class=\"callout\">\n<span class=\"callout-icon\">\u2139</span>\n<div class=\"callout-body\">\n<strong>check --deploy before going live</strong>\n Run <code>python manage.py check --deploy</code> \u2014 it checks 20+ security settings and tells you exactly what to fix.\n </div>\n</div>\n<div class=\"callout tone-tip\">\n<span class=\"callout-icon\"></span>\n<div class=\"callout-body\">\n<strong>Use <code>get_or_create</code> with care</strong>\n The <code>defaults</code> kwarg only applies on creation. Fields outside <code>defaults</code> are used for the lookup \u2014 getting this wrong creates duplicate rows.\n </div>\n</div>\n<h3>One-Liners Worth Knowing</h3>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-label\">python</span></div>\n<pre><span># Safely get one object or None (no exception)</span>\nproduct <span>=</span> Product.objects.<span>filter</span>(slug<span>=</span>slug).<span>first</span>()\n\n<span># Check existence without fetching the object</span>\nexists <span>=</span> Product.objects.<span>filter</span>(pk<span>=</span>pk).<span>exists</span>()\n\n<span># Reverse URL by model instance</span>\n<span>class</span> <span>Product</span>(models.<span>Model</span>):\n <span>def</span> <span>get_absolute_url</span>(<span>self</span>):\n <span>from</span> django.urls <span>import</span> reverse\n <span>return</span> <span>reverse</span>(<span>'products:detail'</span>, kwargs<span>=</span>{<span>'slug'</span>: <span>self</span>.slug})\n\n<span># Chunked processing for large tables (no memory blow-up)</span>\n<span>def</span> <span>chunked_iterator</span>(qs, chunk<span>=</span><span>1000</span>):\n pks <span>=</span> qs.<span>values_list</span>(<span>'pk'</span>, flat<span>=</span><span>True</span>)\n <span>for</span> i <span>in</span> <span>range</span>(<span>0</span>, <span>len</span>(pks), chunk):\n <span>yield from</span> qs.<span>filter</span>(pk__in<span>=</span>pks[i:i<span>+</span>chunk])\n<span># or simply:</span>\n<span>for</span> product <span>in</span> Product.objects.<span>all</span>().<span>iterator</span>(chunk_size<span>=</span><span>500</span>): ...\n\n<span># Format JSON response with status</span>\n<span>from</span> django.http <span>import</span> JsonResponse\n<span>return</span> <span>JsonResponse</span>({<span>'error'</span>: <span>'Not found'</span>}, status<span>=</span><span>404</span>)\n\n<span># Flatten a list from values_list</span>\nids <span>=</span> <span>list</span>(Product.objects.<span>values_list</span>(<span>'id'</span>, flat<span>=</span><span>True</span>))\n\n<span># Date filtering (this month)</span>\n<span>from</span> django.utils <span>import</span> timezone\nnow <span>=</span> timezone.<span>now</span>()\nProduct.objects.<span>filter</span>(\n created_at__year<span>=</span>now.year,\n created_at__month<span>=</span>now.month\n)</pre>\n</div>\n<h3>Recommended Packages</h3>\n<div class=\"table-wrap\">\n<table>\n<tr><th>Package</th><th>Purpose</th></tr>\n<tr><td>django-environ</td><td>12-factor env var config</td></tr>\n<tr><td>django-debug-toolbar</td><td>SQL/query profiling in dev</td></tr>\n<tr><td>django-extensions</td><td>shell_plus, graph_models, etc.</td></tr>\n<tr><td>factory-boy</td><td>Model factories for tests</td></tr>\n<tr><td>pytest-django</td><td>pytest integration + fixtures</td></tr>\n<tr><td>django-filter</td><td>DRF filter backends</td></tr>\n<tr><td>djangorestframework-simplejwt</td><td>JWT auth for DRF</td></tr>\n<tr><td>django-cors-headers</td><td>CORS headers middleware</td></tr>\n<tr><td>django-storages + boto3</td><td>S3 file storage</td></tr>\n<tr><td>whitenoise</td><td>Serve statics in production</td></tr>\n<tr><td>sentry-sdk</td><td>Error monitoring</td></tr>\n<tr><td>django-silk</td><td>Request/SQL profiling</td></tr>\n<tr><td>dj-database-url</td><td>DB URL parsing</td></tr>\n<tr><td>django-csp</td><td>Content-Security-Policy headers</td></tr>\n</table>\n</div>\n</section>";

